       import { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';


function AdminDashboard() {
  const [stats, setStats] = useState({
    totalEvents: 0,
    totalBookings: 0,
    totalRevenue: 0,
    totalUsers: 0
  });
  const [recentBookings, setRecentBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      // Fetch stats (you'll need to create these endpoints in backend)
      // For now, using dummy data
      setStats({
        totalEvents: 25,
        totalBookings: 150,
        totalRevenue: 75000,
        totalUsers: 500
      });

      // Fetch recent bookings
      // const bookingsResponse = await axios.get('http://localhost:5000/api/bookings/all/bookings');
      // setRecentBookings(bookingsResponse.data.bookings.slice(0, 5));
      
      setLoading(false);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div>
        <Navbar />
        <div className="min-h-screen flex items-center justify-center">
          <div className="text-2xl">Loading dashboard...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100">
      <Navbar />

      {/* Header */}
      <div className="bg-gradient-to-r from-blue-600 to-purple-600 py-8">
        <div className="container mx-auto px-4">
          <h1 className="text-4xl font-bold text-white">Admin Dashboard</h1>
          <p className="text-white/90 mt-2">Manage your event platform</p>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">
        
        {/* Stats Cards */}
        <div className="grid md:grid-cols-4 gap-6 mb-8">
          
          {/* Total Events */}
          <div className="bg-white rounded-xl shadow-lg p-6 transform hover:scale-105 transition">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-gray-500 text-sm font-medium">Total Events</p>
                <p className="text-3xl font-bold text-blue-600 mt-2">{stats.totalEvents}</p>
              </div>
              <div className="text-5xl">🎭</div>
            </div>
          </div>

          {/* Total Bookings */}
          <div className="bg-white rounded-xl shadow-lg p-6 transform hover:scale-105 transition">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-gray-500 text-sm font-medium">Total Bookings</p>
                <p className="text-3xl font-bold text-green-600 mt-2">{stats.totalBookings}</p>
              </div>
              <div className="text-5xl">🎫</div>
            </div>
          </div>

          {/* Total Revenue */}
          <div className="bg-white rounded-xl shadow-lg p-6 transform hover:scale-105 transition">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-gray-500 text-sm font-medium">Total Revenue</p>
                <p className="text-3xl font-bold text-purple-600 mt-2">₹{stats.totalRevenue.toLocaleString()}</p>
              </div>
              <div className="text-5xl">💰</div>
            </div>
          </div>

          {/* Total Users */}
          <div className="bg-white rounded-xl shadow-lg p-6 transform hover:scale-105 transition">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-gray-500 text-sm font-medium">Total Users</p>
                <p className="text-3xl font-bold text-pink-600 mt-2">{stats.totalUsers}</p>
              </div>
              <div className="text-5xl">👥</div>
            </div>
          </div>
        </div>

        {/* Quick Actions */}
        <div className="grid md:grid-cols-3 gap-6 mb-8">
          <Link
            to="/admin/create-event"
            className="bg-gradient-to-br from-blue-500 to-blue-600 text-white rounded-xl shadow-lg p-6 hover:shadow-2xl transform hover:scale-105 transition"
          >
            <div className="text-center">
              <div className="text-5xl mb-4">➕</div>
              <h3 className="text-xl font-bold">Create New Event</h3>
              <p className="text-blue-100 mt-2">Add a new event to the platform</p>
            </div>
          </Link>

          <Link
            to="/admin/manage-events"
            className="bg-gradient-to-br from-purple-500 to-purple-600 text-white rounded-xl shadow-lg p-6 hover:shadow-2xl transform hover:scale-105 transition"
          >
            <div className="text-center">
              <div className="text-5xl mb-4">📝</div>
              <h3 className="text-xl font-bold">Manage Events</h3>
              <p className="text-purple-100 mt-2">Edit or delete existing events</p>
            </div>
          </Link>

          <Link
            to="/admin/bookings"
            className="bg-gradient-to-br from-green-500 to-green-600 text-white rounded-xl shadow-lg p-6 hover:shadow-2xl transform hover:scale-105 transition"
          >
            <div className="text-center">
              <div className="text-5xl mb-4">📊</div>
              <h3 className="text-xl font-bold">View All Bookings</h3>
              <p className="text-green-100 mt-2">See all customer bookings</p>
            </div>
          </Link>
        </div>

        {/* Recent Bookings */}
        <div className="bg-white rounded-xl shadow-lg p-6">
          <h2 className="text-2xl font-bold mb-6">Recent Bookings</h2>
          
          {recentBookings.length === 0 ? (
            <div className="text-center py-12">
              <div className="text-6xl mb-4">📦</div>
              <p className="text-gray-500 text-lg">No bookings yet</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b">
                    <th className="text-left py-3 px-4">Booking ID</th>
                    <th className="text-left py-3 px-4">User</th>
                    <th className="text-left py-3 px-4">Event</th>
                    <th className="text-left py-3 px-4">Tickets</th>
                    <th className="text-left py-3 px-4">Amount</th>
                    <th className="text-left py-3 px-4">Status</th>
                  </tr>
                </thead>
                <tbody>
                  {recentBookings.map((booking) => (
                    <tr key={booking._id} className="border-b hover:bg-gray-50">
                      <td className="py-3 px-4">{booking._id.slice(-6)}</td>
                      <td className="py-3 px-4">{booking.user?.name}</td>
                      <td className="py-3 px-4">{booking.event?.name}</td>
                      <td className="py-3 px-4">{booking.numberOfTickets}</td>
                      <td className="py-3 px-4">₹{booking.totalAmount}</td>
                      <td className="py-3 px-4">
                        <span className={`px-3 py-1 rounded-full text-xs font-semibold ${
                          booking.status === 'confirmed' ? 'bg-green-100 text-green-800' :
                          booking.status === 'pending' ? 'bg-yellow-100 text-yellow-800' :
                          'bg-red-100 text-red-800'
                        }`}>
                          {booking.status}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default AdminDashboard;
